    bytes = this.mangafireTransform(bytes, this.mangafireAtob(this.mangafireSeeds32.V), prefixV, prefixV.length, this.mangafireScheduleY);
    bytes = this.mangafireRc4(this.mangafireAtob(this.mangafireRc4Keys.B), bytes);
    var prefixL = this.mangafireAtob(this.mangafirePrefixKeys.L);
    bytes = this.mangafireTransform(bytes, this.mangafireAtob(this.mangafireSeeds32.N), prefixL, prefixL.length, this.mangafireScheduleB);
    bytes = this.mangafireRc4(this.mangafireAtob(this.mangafireRc4Keys.m), bytes);
    var prefixP = this.mangafireAtob(this.mangafirePrefixKeys.p);
    bytes = this.mangafireTransform(bytes, this.mangafireAtob(this.mangafireSeeds32.P), prefixP, prefixP.length, this.mangafireScheduleJ);
    bytes = this.mangafireRc4(this.mangafireAtob(this.mangafireRc4Keys.F), bytes);
    var prefixW = this.mangafireAtob(this.mangafirePrefixKeys.W);
    bytes = this.mangafireTransform(bytes, this.mangafireAtob(this.mangafireSeeds32.k), prefixW, prefixW.length, this.mangafireScheduleE);
    return this.mangafireBtoa(bytes).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
  }

  mangafireNormalizeLanguageCode(lang) {
    var map = { en: 'en', fr: 'fr', es: 'es', 'es-la': 'es-419', pt: 'pt', 'pt-br': 'pt-BR', ja: 'ja', de: 'de', it: 'it', ru: 'ru', ko: 'ko', zh: 'zh', 'zh-cn': 'zh-cn', 'zh-tw': 'zh-tw', ar: 'ar', tr: 'tr' };
    return map[lang] || lang;
  }

  mangafireExtractLanguageCodes(html) {
    var $ = LoadDoc(html);
    var out = [];
    var seen = {};
    $('[data-code][data-title]').each(function(_, e) {
      var code = String(e.attr('data-code') || '').toLowerCase();
      var title = String(e.attr('data-title') || '');
      if (code === 'es' && title.indexOf('LATAM') !== -1) code = 'es-la';
      else if (code === 'pt' && /br/i.test(title)) code = 'pt-br';
      if (!code || seen[code]) return;
      seen[code] = true;
      out.push(code);
    });
    return out;
  }

  async mangafireSearch(query) {
    var q = this.cleanSearchQuery(query);
    if (!q) return [];
    try {
      var vrf = this.mangafireGenerate(q.trim());
      var res = await fetch(this.mangafireApi + '/ajax/manga/search?keyword=' + encodeURIComponent(q).replace(/%20/g, '+') + '&vrf=' + vrf);
      var data = await res.json();
      if (!(data && data.result && data.result.html)) return [];
      var $ = LoadDoc(data.result.html);
      var results = [];
      $('a.unit').each((_, e) => {
        var id = String(e.attr('href') || '').replace('/manga/', '').trim();
        var title = String(e.find('h6').text() || '').trim();
        var image = String(e.find('img').attr('src') || '').trim() || undefined;
        if (!id || !title) return;
        results.push({ id: this.withSource('mangafire', id), title: '[MangaFire] ' + title, synonyms: [title], year: undefined, image: image });
      });
      return results;
    } catch (e) { return []; }
  }

  async mangafireFetchChaptersForLanguage(mangaId, lang) {
    var mangaIdShort = String(mangaId || '').split('.').pop() || '';
    if (lang !== 'pt-br') return [];
    var vrf = this.mangafireGenerate(mangaIdShort + '@chapter@' + lang);
    var res = await fetch(this.mangafireApi + '/ajax/read/' + mangaIdShort + '/chapter/' + lang + '?vrf=' + vrf);
    var data = await res.json();
    var html = data && data.result ? data.result.html || '' : '';
    if (!html) return [];
    var $ = LoadDoc(html);
    var langChapters = [];
    var self = this;
    $('a[data-number][data-id]').each(function(i, e) {
      var url = String(e.attr('href') || '');
      var chapter = String(e.attr('data-number') || '');
      var id = String(e.attr('data-id') || '');
      var title = String(e.attr('title') || '');
      if (!id) return;
      langChapters.push({ id: self.withSource('mangafire', id), url: self.mangafireApi + url, title: '[MangaFire] ' + (title || ('Capítulo ' + chapter)), chapter: chapter, index: 0, language: 'pt-BR' });
    });
    langChapters.reverse();
    for (var i = 0; i < langChapters.length; i++) langChapters[i].index = i;
    return langChapters;
  }

  async mangafireFindChapters(prefixedId) {
    var parts = this.splitSourceId(prefixedId);
    var mangaId = parts.id;
    if (!mangaId) return [];
    try {
      var reslangs = await fetch(this.mangafireApi + '/manga/' + mangaId);
      var htmlLang = await reslangs.text();
      var codes = this.mangafireExtractLanguageCodes(htmlLang);
      var all = [];
      for (var i = 0; i < codes.length; i++) {
        if (codes[i] !== 'pt-br') continue;
        var chapters = await this.mangafireFetchChaptersForLanguage(mangaId, codes[i]);
        all = all.concat(chapters);
      }
      return all;
    } catch (e) { return []; }
  }

  async mangafireFindChapterPages(prefixedId) {
    var parts = this.splitSourceId(prefixedId);
    var chapterId = parts.id;
    if (!chapterId) return [];
    try {
      var vrf = this.mangafireGenerate('chapter@' + chapterId);
      var res = await fetch(this.mangafireApi + '/ajax/read/chapter/' + chapterId + '?vrf=' + vrf);
      var data = await res.json();
      var images = data && data.result ? data.result.images : null;
      if (!images || !images.length) return [];
      var out = [];
      for (var i = 0; i < images.length; i++) out.push({ url: images[i][0], index: i, headers: { Referer: this.mangafireApi } });
      return out;
    } catch (e) { return []; }
  }



  async fetchAniListMeta(query) {
    var q = this.cleanSearchQuery(query);
    if (!q) return null;
    try {
      var gql = 'query ($search: String) { Media(search: $search, type: MANGA) { coverImage { extraLarge large medium } title { romaji english native } synonyms } }';
      var response = await fetch('https://graphql.anilist.co', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
        body: JSON.stringify({ query: gql, variables: { search: q } })
      });
      if (!response.ok) return null;
      var data = await response.json();
      var media = data && data.data ? data.data.Media : null;
      if (!media) return null;
      var synonyms = [];
      var seen = {};
      var pushSyn = function(value) {
        var raw = String(value || '').trim();
        var key = raw.toLowerCase();
        if (!raw || seen[key]) return;
        seen[key] = true;
        synonyms.push(raw);
      };
      if (media.title) {
        pushSyn(media.title.romaji);
        pushSyn(media.title.english);
        pushSyn(media.title.native);
      }
      var extra = media.synonyms || [];
      for (var i = 0; i < extra.length; i++) pushSyn(extra[i]);
      return {
        image: media.coverImage ? (media.coverImage.extraLarge || media.coverImage.large || media.coverImage.medium || undefined) : undefined,
        synonyms: synonyms
      };
    } catch (e) {
      return null;
    }
  }

  async enrichMissingMetadata(results) {
    var out = [];
    for (var i = 0; i < results.length; i++) {
      var item = results[i];
      var cleanTitle = this.cleanSearchQuery(String(item.title || '').replace(/^\[[^\]]+\]\s*/, ''));
      var needsImage = !item.image;
      var needsSynonyms = !item.synonyms || !item.synonyms.length;
      if (needsImage || needsSynonyms) {
        try {
          var meta = await this.fetchAniListMeta(cleanTitle);
          if (meta) {
            if (needsImage && meta.image) item.image = meta.image;
            if (meta.synonyms && meta.synonyms.length) {
              var current = Array.isArray(item.synonyms) ? item.synonyms.slice() : [];
              var seen = {};
              var merged = [];
              for (var a = 0; a < current.length; a++) {
                var c = String(current[a] || '').trim();
                var ck = c.toLowerCase();
                if (!c || seen[ck]) continue;
                seen[ck] = true;
                merged.push(c);
              }
              for (var b = 0; b < meta.synonyms.length; b++) {
                var s = String(meta.synonyms[b] || '').trim();
                var sk = s.toLowerCase();
                if (!s || seen[sk]) continue;
                seen[sk] = true;
                merged.push(s);
              }
              item.synonyms = merged;
            }
          }
        } catch (e) {}
      }
      out.push(item);
    }
    return out;
  }



  async isAdultManga(query) {
    var q = this.cleanSearchQuery(query);
    if (!q) return false;
    try {
      var gql = 'query ($search: String) { Media(search: $search, type: MANGA) { isAdult } }';
      var response = await fetch('https://graphql.anilist.co', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
        body: JSON.stringify({ query: gql, variables: { search: q } })
      });
      if (!response.ok) return false;
      var data = await response.json();
      var media = data && data.data ? data.data.Media : null;
      return !!(media && media.isAdult);
    } catch (e) {
      return false;
    }
  }



  getDisableNsfwConfig() {
    var raw = String('{{disable_nsfw}}' || '').trim().toLowerCase();
    if (!raw || raw.indexOf('{{') === 0) return false;
    return raw === 'true' || raw === '1' || raw === 'yes' || raw === 'on' || raw === 'sim';
  }

  async search(opts) {
    var query = this.cleanSearchQuery(opts && opts.query);
    var expectedYear = opts && opts.year ? Number(opts.year) : undefined;
    if (!query) return [];
    var results = [];
    var disableNsfw = this.getDisableNsfwConfig();
    var adultOnly = disableNsfw ? false : await this.isAdultManga(query);
    if (adultOnly) {
      if (!disableNsfw) { try { results = results.concat(await this.hipercoolSearch(query)); } catch (e) {} }
      if (!disableNsfw) { try { results = results.concat(await this.tiamanhwaSearch(query)); } catch (e) {} }
      if (!results.length) {
        try { results = results.concat(await this.mangaflixSearch(query, expectedYear)); } catch (e) {}
        try { results = results.concat(await this.mangafireSearch(query)); } catch (e) {}
      }
    } else {
      try { results = results.concat(await this.mangaflixSearch(query, expectedYear)); } catch (e) {}
      try { results = results.concat(await this.mangalivreSearch(query)); } catch (e) {}
      if (!disableNsfw) {
        try { results = results.concat(await this.hipercoolSearch(query)); } catch (e) {}
        try { results = results.concat(await this.tiamanhwaSearch(query)); } catch (e) {}
      }
      try { results = results.concat(await this.mangafireSearch(query)); } catch (e) {}
    }
    var deduped = this.dedupeBy(results, function(item) {
      var sourceId = String((item && item.id) || '').trim();
      if (sourceId) return sourceId;
      return String((item && item.title) || '').toLowerCase();
    });
    return await this.enrichMissingMetadata(deduped.slice(0, 75));
  }

  async findChapters(mangaId) {
    var source = this.splitSourceId(mangaId).source;
    if (source === 'mangaflix') return await this.mangaflixFindChapters(mangaId);
    if (source === 'mangalivre') return await this.mangalivreFindChapters(mangaId);
    if (source === 'hipercool') return await this.hipercoolFindChapters(mangaId);
    if (source === 'tiamanhwa') return await this.tiamanhwaFindChapters(mangaId);
    if (source === 'mangafire') return await this.mangafireFindChapters(mangaId);
    return [];
  }

  async findChapterPages(chapterId) {
    var source = this.splitSourceId(chapterId).source;
    if (source === 'mangaflix') return await this.mangaflixFindChapterPages(chapterId);
    if (source === 'mangalivre') return await this.mangalivreFindChapterPages(chapterId);
    if (source === 'hipercool') return await this.hipercoolFindChapterPages(chapterId);
    if (source === 'tiamanhwa') return await this.tiamanhwaFindChapterPages(chapterId);
    if (source === 'mangafire') return await this.mangafireFindChapterPages(chapterId);
    return [];
  }
